UPDATE ${tableName}
SET
    filename = #{filename},
    extname = #{extname},
    update_time = #{updateTime},
    upload_id = #{uploadId},
    original_zip_name = #{originalZipName},
    operator = #{operator}
WHERE content_sha256 = #{contentSha256}

UPDATE ${tableName}
SET
    content_sha256 = #{contentSha256},
    file_size = #{fileSize},
    upload_id = #{uploadId},
    original_zip_name = #{originalZipName},
    operator = #{operator},
    update_time = #{updateTime}
WHERE voice_code = #{voiceCode}
